// === A REMPLIR AVANT DEPLOIEMENT ===
// 1. Token Meta : System User token (Business Manager > Utilisateurs systeme)
//    Droits requis : ads_read, pages_read_engagement, instagram_basic
// 2. ad_account_id : visible sur business.facebook.com (format act_XXXXXXXXXX)
// 3. page_id : Page Facebook > A propos > Identifiant de la page
// 4. ig_user_id : Instagram Business Account ID (via Graph API Explorer)

const TOKEN = $env.META_ACCESS_TOKEN || 'REMPLACER_PAR_TOKEN_META';
const EMAIL_RAPPORT = $env.RAPPORT_EMAIL || 'christoftran@gmail.com';

return [{
  json: {
    token: TOKEN,
    email: EMAIL_RAPPORT,
    date_preset: 'last_30d',
    villes: [
      { nom: 'Metz', ad_account_id: 'act_XXXXXXXXXX', page_id: 'XXXXXXXXXX', ig_user_id: null, budget_alloue: 5000 },
      { nom: 'Bordeaux', ad_account_id: 'act_XXXXXXXXXX', page_id: 'XXXXXXXXXX', ig_user_id: null, budget_alloue: 5000 },
      { nom: 'Evreux', ad_account_id: 'act_XXXXXXXXXX', page_id: 'XXXXXXXXXX', ig_user_id: null, budget_alloue: 5000 },
      { nom: 'Nevers', ad_account_id: 'act_XXXXXXXXXX', page_id: null, ig_user_id: 'XXXXXXXXXX', budget_alloue: 5000 }
    ]
  }
}];

const config = $input.first().json;
const { token, villes, date_preset } = config;
const BASE = 'https://graph.facebook.com/v19.0';

const get = async (url) => {
  const r = await fetch(url);
  const data = await r.json();
  if (data.error) throw new Error(`Meta API: ${data.error.message}`);
  return data;
};

const recommander = (impressions, reach, clicks) => {
  const ctr = impressions > 0 ? clicks / impressions * 100 : 0;
  if (impressions < 300) return { action: 'Donnees insuffisantes.', couleur: '#9ca3af' };
  if (reach > 50000 && ctr >= 1) return { action: 'Relancer massivement.', couleur: '#16a34a' };
  if (ctr >= 2 || (ctr >= 1 && impressions > 10000)) return { action: 'Augmenter le budget.', couleur: '#16a34a' };
  if (ctr >= 0.5 && impressions >= 3000) return { action: 'Maintenir.', couleur: '#2563eb' };
  if (ctr >= 0.2 && impressions >= 1000) return { action: 'Garder.', couleur: '#2563eb' };
  if (ctr < 0.1 && impressions >= 5000) return { action: 'Stopper. Trop cher.', couleur: '#dc2626' };
  if (impressions < 3000 && ctr < 0.3) return { action: 'Stopper.', couleur: '#dc2626' };
  return { action: 'A surveiller.', couleur: '#f59e0b' };
};

const results = [];

for (const ville of villes) {
  let campagnesAnalysees = [];
  try {
    const insightsUrl = `${BASE}/${ville.ad_account_id}/insights?fields=campaign_name,campaign_id,impressions,reach,clicks,actions,spend&level=campaign&date_preset=${date_preset}&limit=50&access_token=${token}`;
    const insightsData = await get(insightsUrl);
    const campaigns = insightsData.data || [];

    campagnesAnalysees = campaigns.map(c => {
      const impressions = parseInt(c.impressions) || 0;
      const reach = parseInt(c.reach) || 0;
      const clicks = parseInt(c.clicks) || 0;
      const spend = parseFloat(c.spend) || 0;
      const actions = c.actions || [];
      const interactions = parseInt(actions.find(a => a.action_type === 'post_engagement')?.value || 0);
      const ctr = impressions > 0 ? (clicks / impressions * 100).toFixed(2) : '0.00';
      const { action, couleur } = recommander(impressions, reach, clicks);
      return { nom: c.campaign_name, impressions, reach, clics: clicks, interactions, spend, ctr, action, couleur };
    }).sort((a, b) => b.impressions - a.impressions);
  } catch (e) {
    console.log(`Erreur insights pour ${ville.nom}:`, e.message);
  }

  let fbFollowers = null;
  let igFollowers = null;
  try {
    if (ville.page_id) {
      const pageUrl = `${BASE}/${ville.page_id}?fields=followers_count,instagram_business_account{followers_count}&access_token=${token}`;
      const pageData = await get(pageUrl);
      fbFollowers = pageData.followers_count ?? null;
      igFollowers = pageData.instagram_business_account?.followers_count ?? null;
    } else if (ville.ig_user_id) {
      const igUrl = `${BASE}/${ville.ig_user_id}?fields=followers_count&access_token=${token}`;
      const igData = await get(igUrl);
      igFollowers = igData.followers_count ?? null;
    }
  } catch (e) {
    console.log(`Erreur stats page pour ${ville.nom}:`, e.message);
  }

  const totalDepense = campagnesAnalysees.reduce((s, c) => s + c.spend, 0);
  const budgetRestant = ville.budget_alloue - totalDepense;
  const tauxDepense = totalDepense / ville.budget_alloue;

  let actionBudget;
  if (tauxDepense < 0.10) actionBudget = 'Depense tres faible - accelerer.';
  else if (tauxDepense < 0.20) actionBudget = 'Depense en retard - accelerer.';
  else if (tauxDepense > 0.80) actionBudget = 'Budget presque epuise - prevoir recharge.';
  else actionBudget = 'Rythme de depense normal.';

  let actionAudience;
  if (igFollowers === null && !ville.ig_user_id) actionAudience = 'Creer le compte Instagram.';
  else if ((igFollowers || 0) < 50) actionAudience = 'Audience IG tres faible - lancer un concours.';
  else if ((fbFollowers || 0) + (igFollowers || 0) < 500) actionAudience = 'Audience faible - booster avec publicite.';
  else actionAudience = 'Continuer la croissance.';

  results.push({
    ville: ville.nom,
    campagnes: campagnesAnalysees,
    audience: { fb: fbFollowers, ig: igFollowers, action: actionAudience },
    budget: { alloue: ville.budget_alloue, depense: totalDepense, restant: budgetRestant, action: actionBudget },
    email: config.email
  });
}

return results.map(r => ({ json: r }));
